import React, { useState } from 'react';
import './App.css';
import HomePage from './component/HomePage';
import AddRoomPage from './component/AddRoomPage';
import {BrowserRouter as Router, Routes , Route} from 'react-router-dom';
//import {Provider} from './contextAPI'

function App() {
  const [rooms, setRooms] = useState([])
  const [currentRoom, setCurrentRoom] = useState("")
  const [room, setRoom] = useState({})

  let addRoom=(room)=>{
    let r=rooms
    r.push(room)
    setRooms(r)
  }

  return (
    <div>
      {displayPage()}

      <div className="App">
      <Provider value={{firstN: data, seondN: data2}}>
        <Header />
      </Provider>

      <Router>
      <Navbar />
        <Routes>
          <Route path={'/'} element={<HomePage rooms={rooms} />} />
          <Route path={'/addRoom'} element={<AddRoomPage addRoom={addRoom}/>} />
          <Route path={'/roomDeco'} element={<AddDecoPage />} />
          <Route path={'/'+currentRoom.name} element={<EditRoom room={room} />} />
        </Routes>
      </Router>

      <Footer />
    </div>
    </div>)}
export default App;
